import{_ as b,o as e,c as a,j as r,a as t,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"皮卡丘","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/皮卡丘.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/皮卡丘.md"}'),n={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/皮卡丘.md"};function s(o,p,l,_,i,c){return e(),a("div",null,[...p[0]||(p[0]=[r("h1",{id:"皮卡丘",tabindex:"-1"},[t("皮卡丘 "),r("a",{class:"header-anchor",href:"#皮卡丘","aria-label":'Permalink to "皮卡丘"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004D")])])],-1),d('<h1 id="皮卡丘-1" tabindex="-1">皮卡丘 <a class="header-anchor" href="#皮卡丘-1" aria-label="Permalink to &quot;皮卡丘&quot;">​</a></h1><p>【皮丘】<br> D+500<br> 独立随从</p><p>身体小巧，却能够释放出足以让成年人麻痹的电击，但是连它自己也会吓一跳。仍然不擅长蓄电。惊讶或者发笑时，就会立刻进行放电。<br> 系别：电系</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量4<br> ■敏捷6<br> ■耐力2<br> ▓▓心智属性<br> ■智力2<br> ■感知6<br> ■决心2<br> ▓▓互动属性<br> ■风度4<br> ■操控2<br> ■沉着4</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动3-反射3-投掷3<br> ■求生3-强韧3<br> ■射击1<br> ■武技5-拳5</p><p>▓▓心智系<br> ■学识5-魔法5<br> ■器用1<br> ■手艺1<br> ■专注3-意志3</p><p>▓▓互动系<br> ■洞察1<br> ■隐秘1<br> ■表达1<br> ■社交3-交涉3</p><p>▓▓▓▓衍生属性值<br> ▓体积 2<br> ▓速度 15米<br> ▓先攻 10<br> ▓防御 6+1<br> ▓生命值 4<br> ▓意志力池 6<br> ▓意志 8+1<br> ▓反射 12+2<br> ▓强韧 8+1<br> ▓侦查 8+1<br> ▓敏感范围 140米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的附加成功达到1点时会获得一个花招动作，达到4点时会将基础的移动动作升级为杂技动作，敏捷上的每1点附加成功会提供3米额外移速<br> 耐力上的每1点附加成功会为其提供5点额外的生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：</p><p>普通攻击：力量/敏捷+武技+拳+天生武器伤害=13+1造成严重伤害。</p><p>宝可梦技艺近战攻击预设：力量/敏捷+武技+拳+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量/敏捷+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：智力/感知+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御6+1<br> ▓▓▓▓性别：<br> ▓▓▓▓特性：</p><p>【电系宝可梦】：使用电系技能时，攻击检定获得3dp雷电能量加值。</p><p>【家喻户晓】：皮丘是皮卡丘的退化型，因其进化型的鼎鼎大名，皮丘的人气也颇为可观。皮丘可以站立在训练家的肢体上，当皮丘与训练家同处于一个场景时，训练家在社交技能检定上获得3dp的表现加值。</p><p>▓▓▓▓装备位：</p><p>▓▓▓▓亲密度： /250</p><p>▓▓▓▓可学习技能：</p><p>电系技能：电击 雷电拳 伏特替换 十万伏特 电网 打雷 放电</p><p>水系技能：冲浪</p><p>恶系技能：诡计 投掷 小偷</p><p>草系技能：打草结</p><p>超能系技能：高速移动 光墙</p><p>一般系技能：守住 硬撑 高速星星 泰山压顶 替身 再来一次 神速 击掌奇袭</p><p>妖精系技能：嬉闹<br> ▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><p>———————————————————<br> 【皮卡丘】<br> 由皮丘支付10xp进化而来，皮丘进化必须要亲密度达到120以上。<br> 独立随从<br> 皮卡丘视为C级召唤物。<br> 皮卡丘仅能由皮丘进化而来，不可单独购买。</p><p>越是能制造出强大电流的皮卡丘，脸颊上的囊就越柔软，同时也越有伸展性。皮卡丘们把尾巴贴在一起交换电流，其实是在互相打招呼。</p><p>系别：电系</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量9<br> ■敏捷11<br> ■耐力6<br> ▓▓心智属性<br> ■智力6<br> ■感知11<br> ■决心6<br> ▓▓互动属性<br> ■风度9<br> ■操控6<br> ■沉着9</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动5-反射5-投掷5<br> ■求生5-强韧5<br> ■射击1<br> ■武技8-拳8</p><p>▓▓心智系<br> ■学识8-魔法8<br> ■器用1<br> ■手艺1<br> ■专注5-意志5</p><p>▓▓互动系<br> ■洞察1<br> ■隐秘1<br> ■表达1<br> ■社交5-交涉5</p><p>▓▓▓▓衍生属性值<br> ▓体积 4<br> ▓速度 30米<br> ▓先攻 20<br> ▓防御 11+2<br> ▓生命值 15<br> ▓意志力池 17<br> ▓意志 17+3<br> ▓反射 22+4<br> ▓强韧 17+3<br> ▓侦查 17+2<br> ▓敏感范围 260米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的附加成功达到1点时会获得一个花招动作，达到4点时会将基础的移动动作升级为杂技动作，敏捷上的每1点附加成功会提供3米额外移速<br> 耐力上的每1点附加成功会为其提供5点额外的生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：</p><p>普通攻击预设：敏捷11+武技8+拳8+天生武器伤害3L+机运4=35+5</p><p>宝可梦技艺近战攻击预设：力量/敏捷+武技+拳+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量/敏捷+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：智力/感知+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御11+2 机运防御4<br> ▓▓▓▓性别：<br> ▓▓▓▓特性：</p><p>【提升：家喻户晓】：即便你不知道什么是宝可梦，你也有可能知道什么是皮卡丘。宝可梦的代表，萌物的经典形象。<br> 皮卡丘可以站立在训练家的肢体上，当皮卡丘与训练家同处于一个场景时，训练家在社交技能检定上获得6dp的表现加值。<br> 皮卡丘在独立行动时，社交检定同样具有6dp表现加值。</p><p>【主角的伙伴】：从宝可梦这一概念出现在人们视野中时，皮卡丘就已经是主角的伙伴了。外行以为它只是吉祥物，内行管它叫皮神。皮卡丘的攻击和防御检定上获得4dp的机运加值。</p><p>【皮卡皮卡。。皮！卡！丘~】：即便是当年那只只会啾啾的皮丘，经历了与你一起的多场战斗后也成长为一个经验老道的战士了。现在皮卡丘的全身视为3L的天生武器。</p><p>【静电】：皮卡丘的电系攻击技能命中后，攻击附带1点不可豁免的麻痹点数（环境来源）。</p><p>【电系宝可梦】：使用电系技能时，攻击检定获得3dp雷电能量加值。</p><p>▓▓▓▓装备位：</p><p>皮卡丘可购买专属装备：【电气球】。<br> 【电气球】 B+2000<br> 该效果仅能在皮卡丘及搭档皮卡丘装备时生效。<br> 效果：宝可梦在进行攻击检定时可以获得等同于自己敏捷属性点的能量加值与5点来自雷电能量的附加成功。</p><p>▓▓▓▓亲密度： /250</p><p>▓▓▓▓可学习技能：</p><p>可学习技能机器同皮丘。</p><p>额外支付B+2000可以学习皮卡丘专属技能：【伏特攻击】。</p><p>【伏特攻击】<br> 指挥动作：整轮动作<br> 宝可梦消耗动作：整轮动作<br> 效果：电系物理技能，皮卡丘承受6点不可减免吸收的雷电严重伤害，进行一次冲锋攻击。本次攻击具有等同于皮卡丘敏捷属性点的雷电能量加值以及3点来自于雷电能量的附加成功。本次攻击额外具有【8加骰】【湮灭】【法破】【接触攻击】特性。<br> 差价升级至A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> 则本技能攻击中皮卡丘承受的不可吸收的严重伤害提升至12点，攻击中来自雷电能量的附加成功提升至9，本次冲锋可以曲线冲锋并额外获得360米移动速度，无视A级及以下的困难地形效果，攻击命中后附带等同于伤害值的麻痹点数，正常豁免。这次攻击忽略对手的洞察防御，这是一个A级幻象效果来源（视为皮卡丘以对手难以看清的速度冲锋）。</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><p>————————————————————<br> 【搭档皮卡丘】<br> 由皮卡丘支付21xp进化而来，皮卡丘亲密度至少达到220以上<br> 独立随从<br> 搭档皮卡丘视为B级召唤物。<br> 搭档皮卡丘仅能由皮卡丘进化而来，不可单独购买。<br> （特别声明：应该不会有人不期待在这里看到搭档皮卡丘吧？不会有人真的期待B级进化型出现的是雷丘吧？反正不管咯，我想看的是搭档皮卡丘咯，我就写搭档皮卡丘咯。）</p><p>戴着的是伙伴训练家的帽子。帽子上承载着许许多多在不同地区冒险的回忆。</p><p>▓▓▓▓属性<br> ▓▓生理属性<br> ■力量14<br> ■敏捷16<br> ■耐力11<br> ▓▓心智属性<br> ■智力11<br> ■感知16<br> ■决心11<br> ▓▓互动属性<br> ■风度14<br> ■操控11<br> ■沉着14</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动8-反射8-投掷8<br> ■求生8-强韧8<br> ■射击1<br> ■武技11-拳11</p><p>▓▓心智系<br> ■学识11-魔法11<br> ■器用1<br> ■手艺1<br> ■专注8-意志8</p><p>▓▓互动系<br> ■洞察1<br> ■隐秘1<br> ■表达1<br> ■社交8-交涉8</p><p>▓▓▓▓衍生属性值<br> ▓体积 4<br> ▓速度 （力量【14】+敏捷【16】+体积【4】+每1点敏捷上的附加获得3移动速度）=43米<br> ▓先攻 （敏捷【16】+沉着【14】）=30<br> ▓防御 （敏捷感知的平均值【16】+较高者的附加成功【3】）= 16+3<br> ▓生命值 （耐力【11】+体积【4】+耐力附加【2 】×5）=25<br> ▓意志力池 （决心【11】+沉着【14】+决心附加【2 】×2）=29<br> ▓意志 （决心【11】+专注8+意志【8】）=31+5<br> ▓反射 （敏捷【16】+运动8+反射【8】）=34+6<br> ▓强韧 （耐力【11】+生存8+强韧【8】）=29+5<br> ▓侦查 （感知【16】+洞察1+侦查【】）=22+3<br> ▓敏感范围 （感知【16】*20米+感知上的附加成功【3 】*20米）=380米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的附加成功达到1点时会获得一个花招动作，达到4点时会将基础的移动动作升级为杂技动作，敏捷上的每1点附加成功会提供3米额外移速<br> 耐力上的每1点附加成功会为其提供5点额外的生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：</p><p>普通攻击预设：敏捷16+武技11+拳11+天生武器伤害3+机运8+1=51+8</p><p>宝可梦技艺近战攻击预设：力量/敏捷+武技+拳+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量/敏捷+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：智力/感知+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御16+3 机运防御8+1<br> ▓▓▓▓性别：<br> ▓▓▓▓特性：</p><p>【提升：家喻户晓】：即便你不知道什么是宝可梦，你也有可能知道什么是皮卡丘。宝可梦的代表，萌物的经典形象。皮卡丘在社交上的表现加值提升至9dp。</p><p>【提升：主角的伙伴】：所有喜欢皮卡丘的训练家，都渴望一只搭档皮卡丘，因为真正配得上皮神称号的只有它。搭档皮卡丘的攻击和防御检定上获得的机运加值提升至8dp，并各获得1点来自于机运的附加成功。</p><p>【提升：静电】：搭档皮卡丘对雷电能量的掌握已经是本能了，若它还是电到你了，不要怀疑，它就是故意的。搭档皮卡丘的攻击命中后附带的不可豁免的麻痹点数（环境来源）提升至2。</p><p>【电系宝可梦】：使用电系技能时，攻击检定获得3dp雷电能量加值。<br> ▓▓▓▓装备位：</p><p>▓▓▓▓亲密度： /250</p><p>▓▓▓▓可学习技能：</p><p>同皮卡丘，包括专属技能【伏特攻击】。</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',91)])])}const m=b(n,[["render",s]]);export{f as __pageData,m as default};
